const listB5ClaimItems = `-- name: ListB5ClaimItems :many
SELECT group_id, resource_id, requested_quantity, remaining_quantity FROM b5_claim_items WHERE group_id = $1 ORDER BY resource_id
`

func (q *Queries) ListB5ClaimItems(ctx context.Context, groupID string) ([]*B5ClaimItem, error) {
	rows, err := q.db.Query(ctx, listB5ClaimItems, groupID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []*B5ClaimItem{}
	for rows.Next() {
		var i B5ClaimItem
		if err := rows.Scan(
			&i.GroupID,
			&i.ResourceID,
			&i.RequestedQuantity,
			&i.RemainingQuantity,
		); err != nil {
			return nil, err
		}
		items = append(items, &i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

